// Some portions generated by Co-Pilot
import { fetchLatestAssets } from "@/services/adoptiumApi";
import type { BinaryAssetView, TemurinAssets, OS, Arch } from "@/types/temurin";

export async function loadLatestAssets(
  version: number | "any",
  os: OS,
  architecture: Arch,
): Promise<TemurinAssets> {
  const versionToUse = version === "any" ? "feature" : version;

  const params: Record<string, string> = {};
  if (os !== "any") params.os = os;
  if (architecture !== "any") params.architecture = architecture;

  const raw: BinaryAssetView[] = await fetchLatestAssets(versionToUse, params)
    .then((data) => data as unknown as BinaryAssetView[])
    .catch(() => []);

  const assets: TemurinAssets = [] as unknown as TemurinAssets;

  raw.forEach((view) => {
    const imgType = (view.binary?.image_type ?? "").toUpperCase();
    if (imgType === "SOURCES") {
      assets.source = view;
      return;
    }
    if (!["INSTALLER", "JDK", "JRE"].includes(imgType)) {
      return;
    }
    assets.push(view);
  });

  return assets;
}

// Re-export types for consumers that previously imported from this file
export type { BinaryAssetView, TemurinAssets };
